import request from '@/utils/request'

// 认证相关的核心功能
export const auth = {
  // 密码登录
  loginWithPassword: (data) => {
    return request.post('/api/v1/users/auth/login/password/', data)
  },

  // 退出登录
  logout: () => {
    const refreshToken = localStorage.getItem('refresh_token')
    if (!refreshToken) return
    return request.post('/api/v1/users/auth/logout/', { refresh: refreshToken })
  },

  // 刷新 token
  refreshToken: (data) => {
    return request.post('/api/v1/users/auth/token/refresh/', data)
  },

  // 更新用户名（昵称）
  updateUsername: (data) => {
    return request.post('/api/v1/users/account/username/', data)
  },

  // 更新密码
  updatePassword: (data) => {
    return request.post('/api/v1/users/account/password/', data)
  },

  // 发送验证码
  sendVerifyCode: (data) => {
    return request.post('/api/v1/users/verify-code/send/', data)
  },

  // 更换手机号
  changePhone: (data) => {
    return request.post('/api/v1/users/phone/change/', data)
  },

  // 删除账户
  deleteAccount: (data) => {
    return request.post('/api/v1/users/account/delete/', data)
  },

  // 获取用户信息
  getUserInfo: () => {
    return request.get('/api/v1/users/info/')
  }
}

export default auth
